sn_aia_tool.script:
(function(inputs) {
    var claimSysId = inputs.claim_sys_id;
    var decision = inputs.decision;
    var analysis = inputs.analysis;
    var policyRef = inputs.policy_reference;
    var gr = new GlideRecordSecure('x_snc_medwc_auto_0_warranty_claim');
    if (!gr.get(claimSysId)) {
        return JSON.stringify({ status: 'error', message: 'Claim not found: ' + claimSysId });
    }
    var now = new GlideDateTime();
    var workNote = '[AI Agent Decision: ' + decision.toUpperCase() + ']\n\n';
    workNote += 'Analysis:\n' + analysis + '\n\n';
    workNote += 'Policy Reference: ' + policyRef + '\n\n';
    workNote += 'Decision made at: ' + now.getDisplayValue();
    gr.work_notes = workNote;
    gr.update();
    return JSON.stringify({
        status: 'success',
        message: 'Work note added to claim ' + gr.getValue('number'),
        claim_number: gr.getValue('number')
    });
})(inputs);
